    if (n == 0) return 0;

    // Sort the array to check if it is already non-decreasing
    int64_t* sorted = (int64_t*)malloc(n * sizeof(int64_t));
    for (int i = 0; i < n; i++) {
        sorted[i] = nums[i];
    }
    for (int i = 1; i < n; i++) {
        if (sorted[i] < sorted[i - 1]) {
            break;
        }
    }

    // If already sorted, return 0
    if (sorted[0] == nums[0] && sorted[1] == nums[1] && sorted[2] == nums[2]) {
        return 0;
    }

    // Try all possible k values from 0 to n-1
    for (int64_t k = n - 1; k >= 0; k--) {
        // Check if there exists a pair of elements in nums that can be swapped to sort the array
        bool can_sort = false;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if ((nums[i] & nums[j]) == k) {
                    // Swap the elements and check if the array is sorted
                    int64_t temp = nums[i];
                    nums[i] = nums[j];
                    nums[j] = temp;

                    bool is_sorted = true;
                    for (int m = 1; m < n; m++) {
                        if (nums[m] < nums[m - 1]) {
                            is_sorted = false;
                            break;
                        }
                    }

                    if (is_sorted) {
                        can_sort = true;
                        // Restore the original array
                        nums[i] = temp;
                        nums[j] = nums[i];
                        break;
                    }

                    // Restore the original array
                    nums[i] = temp;
                    nums[j] = nums[i];
                    break;
                }
            }
            if (can_sort) break;
        }
        if (can_sort) {
            return k;
        }
    }

    return 0;
}
